package form;
import controller.TabunganController;import util.UIUtils;import javax.swing.*;import javax.swing.table.DefaultTableModel;import java.awt.*;import java.io.File;
public class TabunganForm extends JPanel{TabunganController c=new TabunganController();DefaultTableModel m=new DefaultTableModel(new String[]{"Tanggal","Jenis","Nominal","Saldo Akhir","Keterangan"},0);public TabunganForm(){setLayout(new BorderLayout());JPanel p=UIUtils.page("Tabungan Siswa");JTextField siswa=UIUtils.textField(6),nom=UIUtils.textField(10),ket=UIUtils.textField(20);JComboBox<String> jenis=new JComboBox<>(new String[]{"SETOR","TARIK"});JButton sim=UIUtils.button("Proses Mutasi",UIUtils.BLUE),pdf=UIUtils.button("Cetak Rekap PDF",UIUtils.ORANGE),load=UIUtils.button("Buku Digital",UIUtils.CYAN);sim.addActionListener(e->{try{c.mutasi(Integer.parseInt(siswa.getText()),(String)jenis.getSelectedItem(),Double.parseDouble(nom.getText()),ket.getText());reload(Integer.parseInt(siswa.getText()));}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});load.addActionListener(e->{try{reload(Integer.parseInt(siswa.getText()));}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});pdf.addActionListener(e->{try{c.cetakRekapPdf(new File("rekap-tabungan.pdf"),Integer.parseInt(siswa.getText()));JOptionPane.showMessageDialog(this,"PDF dibuat");}catch(Exception ex){JOptionPane.showMessageDialog(this,ex.getMessage());}});p.add(UIUtils.toolbar(UIUtils.formLabel("ID Siswa"),siswa,UIUtils.formLabel("Jenis"),jenis,UIUtils.formLabel("Nominal"),nom,UIUtils.formLabel("Ket"),ket,sim,load,pdf),BorderLayout.NORTH);p.add(UIUtils.tableScroll(new JTable(m)));add(p);}void reload(int s)throws Exception{m.setRowCount(0);for(Object[] r:c.riwayat(s))m.addRow(r);}}
